// ============================================================================
// SplitHandle Widget - Horizontal resizable divider with grip dots
// ============================================================================

struct SplitHandle : Widget {
    // Appearance
    float handle_height = CommitHistory::SPLIT_HANDLE_HEIGHT;  // 4.0f
    uint32_t bg_color = Theme::BG_TERTIARY;
    uint32_t dot_color = Theme::TEXT_MUTED;
    uint32_t dot_color_hover = Theme::TEXT_SECONDARY;
    int dot_count = 5;
    float dot_spacing = 8.0f;
    float dot_radius = 1.5f;

    // State
    bool dragging = false;
    float drag_start_y = 0.0f;

    // Callbacks
    void (*on_drag)(SplitHandle* handle, float delta_y, void* user_data) = nullptr;
    void (*on_drag_end)(SplitHandle* handle, void* user_data) = nullptr;
    void* user_data = nullptr;

    SplitHandle() {
        flags |= WidgetFlags::CapturesMouse;
        preferred_height = handle_height;
        height_mode = SizeMode::Fixed;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_height = handle_height;
        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        // Draw background
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + rect.height
        );
        ctx.fill_rect(bg_rect, bg_color);

        // Draw grip dots in center
        float center_x = rect.x + rect.width / 2.0f;
        float center_y = rect.y + rect.height / 2.0f;

        bool is_hovered = (flags & WidgetFlags::Hovered) || dragging;
        uint32_t color = is_hovered ? dot_color_hover : dot_color;
        ctx.brush->SetColor(color_from_argb(color));

        int half_count = dot_count / 2;
        for (int i = -half_count; i <= half_count; i++) {
            ctx.target->FillEllipse(
                D2D1::Ellipse(D2D1::Point2F(center_x + i * dot_spacing, center_y), dot_radius, dot_radius),
                ctx.brush
            );
        }
    }

    bool on_mouse_enter() override {
        flags |= WidgetFlags::Hovered;
        set_dirty();
        return true;
    }

    bool on_mouse_leave() override {
        if (!dragging) {
            flags &= ~WidgetFlags::Hovered;
            set_dirty();
        }
        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)button;
        dragging = true;
        // Store absolute Y at drag start (y is relative here, convert to absolute)
        drag_start_y = rect.y + y;
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if (dragging) {
            dragging = false;
            if (on_drag_end) {
                on_drag_end(this, user_data);
            }
            set_dirty();
        }
        return true;
    }

    bool on_mouse_move(float x, float y) override {
        (void)x;
        if (dragging) {
            // When captured, dispatcher passes absolute coordinates
            // Calculate delta from stored absolute drag start position
            float delta = y - drag_start_y;
            drag_start_y = y;  // Update for next frame

            if (on_drag && delta != 0.0f) {
                on_drag(this, delta, user_data);
            }
            return true;
        }
        return false;
    }
};

// ============================================================================
// DragHandle Widget - Vertical resize handle for sidebar edge
// ============================================================================

struct DragHandle : Widget {
    // Appearance
    float handle_width = Sidebar::DRAG_HANDLE_HIT;      // 4.0f hit area
    float visible_width = Sidebar::DRAG_HANDLE_VISIBLE; // 1.0f line width
    uint32_t color_normal = Theme::BORDER;
    uint32_t color_hover = Theme::TEXT_MUTED;

    // Constraints
    float min_width = Sidebar::WIDTH_MIN;   // 180.0f
    float max_width = Sidebar::WIDTH_MAX;   // 400.0f

    // State
    bool dragging = false;
    float drag_start_x = 0.0f;
    float drag_start_width = 0.0f;

    // Callbacks
    void (*on_drag)(DragHandle* handle, float new_width, void* user_data) = nullptr;
    void (*on_drag_end)(DragHandle* handle, void* user_data) = nullptr;
    void* user_data = nullptr;

    DragHandle() {
        flags |= WidgetFlags::CapturesMouse;
        preferred_width = handle_width;
        width_mode = SizeMode::Fixed;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_width = handle_width;
        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        // Draw vertical line at right edge of handle area
        float line_x = rect.x + rect.width - visible_width;

        bool is_hovered = (flags & WidgetFlags::Hovered) || dragging;
        uint32_t color = is_hovered ? color_hover : color_normal;

        ctx.brush->SetColor(color_from_argb(color));
        ctx.target->DrawLine(
            D2D1::Point2F(line_x, rect.y),
            D2D1::Point2F(line_x, rect.y + rect.height),
            ctx.brush,
            visible_width
        );
    }

    bool on_mouse_enter() override {
        flags |= WidgetFlags::Hovered;
        set_dirty();
        return true;
    }

    bool on_mouse_leave() override {
        if (!dragging) {
            flags &= ~WidgetFlags::Hovered;
            set_dirty();
        }
        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)y; (void)button;
        dragging = true;
        // Store absolute X at drag start (x is relative here, convert to absolute)
        drag_start_x = rect.x + x;
        // Parent widget sets drag_start_width when drag begins
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if (dragging) {
            dragging = false;
            if (on_drag_end) {
                on_drag_end(this, user_data);
            }
            set_dirty();
        }
        return true;
    }

    bool on_mouse_move(float x, float y) override {
        (void)y;
        if (dragging) {
            // When captured, dispatcher passes absolute coordinates
            // Calculate delta from stored absolute drag start position
            float delta = x - drag_start_x;
            float new_width = drag_start_width + delta;

            // Clamp to constraints
            if (new_width < min_width) new_width = min_width;
            if (new_width > max_width) new_width = max_width;

            if (on_drag) {
                on_drag(this, new_width, user_data);
            }
            return true;
        }
        return false;
    }
};

// ============================================================================
// SidebarWidget - Unified container for entire sidebar
// ============================================================================

struct SidebarWidget : Widget {
    // Dimensions
    float sidebar_width = Sidebar::WIDTH_DEFAULT;
    float split_ratio = 0.4f;  // Branches section ratio (40% = branches, 60% = files)

    // Child widgets (not owned - parent allocates from arena)
    Widget* header = nullptr;               // SidebarHeaderWidget content
    Widget* commit_header = nullptr;        // CommitViewHeader (shown above file_scroll in commit view)
    ScrollContainer* file_scroll = nullptr; // File lists scroll container
    SplitHandle* split_handle = nullptr;    // Between files and branches
    ScrollContainer* branch_scroll = nullptr; // Branch tree + stashes
    DragHandle* drag_handle = nullptr;      // Sidebar resize

    // Visual state
    bool show_file_border = false;  // Accent border around file list (commit view mode)

    // Callbacks
    void (*on_width_changed)(SidebarWidget* sidebar, float new_width, void* user_data) = nullptr;
    void (*on_split_changed)(SidebarWidget* sidebar, float new_ratio, void* user_data) = nullptr;
    void* user_data = nullptr;

    SidebarWidget() {
        flags |= WidgetFlags::RendersOwnChildren;  // We handle child rendering
        flags |= WidgetFlags::ClipChildren;
    }

    void measure(const LayoutConstraints& constraints) override {
        // Sidebar measures to fill available space
        preferred_width = sidebar_width;
        preferred_height = constraints.max_height;

        float content_width = sidebar_width - Sidebar::DRAG_HANDLE_HIT;

        // Measure header first to get its height
        float header_height = 0.0f;
        if (header) {
            LayoutConstraints header_c = {0, content_width, 0, FLT_MAX};
            header->measure(header_c);
            header_height = header->preferred_height;
        }

        // Measure commit header if visible (sits between header and file_scroll)
        float commit_header_height = 0.0f;
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            LayoutConstraints commit_c = {0, content_width, 0, FLT_MAX};
            commit_header->measure(commit_c);
            commit_header_height = commit_header->preferred_height;
        }

        // Calculate heights for scroll sections (same logic as layout)
        float available_height = constraints.max_height;
        float scrollable_height = available_height - header_height - commit_header_height;
        float split_handle_height = split_handle ? split_handle->handle_height : 4.0f;
        float files_height = scrollable_height * (1.0f - split_ratio) - split_handle_height / 2.0f;
        float branches_height = scrollable_height * split_ratio - split_handle_height / 2.0f;

        // Measure file scroll container - this propagates measure to its children
        // which sets up content_height for scrollbar visibility
        if (file_scroll) {
            LayoutConstraints file_c = {0, content_width, 0, files_height};
            file_scroll->measure(file_c);
        }

        // Measure branch scroll container
        if (branch_scroll) {
            LayoutConstraints branch_c = {0, content_width, 0, branches_height};
            branch_scroll->measure(branch_c);
        }

        Widget::measure(constraints);
    }

    void layout() override {
        // Calculate layout regions
        float content_width = sidebar_width - Sidebar::DRAG_HANDLE_HIT;
        float available_height = rect.height;
        float y = rect.y;

        // 1. Header (fixed height)
        float header_height = 0.0f;
        if (header) {
            header_height = header->preferred_height;
            header->rect.x = rect.x;
            header->rect.y = y;
            header->rect.width = content_width;
            header->rect.height = header_height;
            header->layout();
            y += header_height;
        }

        // 2. Commit header (if visible, fixed height, outside scrollviewer)
        float commit_header_height = 0.0f;
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            commit_header_height = commit_header->preferred_height;
            commit_header->rect.x = rect.x;
            commit_header->rect.y = y;
            commit_header->rect.width = content_width;
            commit_header->rect.height = commit_header_height;
            commit_header->layout();
            y += commit_header_height;
        }

        // Remaining height for scrollable sections
        float scrollable_height = available_height - header_height - commit_header_height;
        float split_handle_height = split_handle ? split_handle->handle_height : 4.0f;

        // Split between files (top) and branches (bottom)
        float files_height = scrollable_height * (1.0f - split_ratio) - split_handle_height / 2.0f;
        float branches_height = scrollable_height * split_ratio - split_handle_height / 2.0f;

        // 3. File scroll container
        if (file_scroll) {
            file_scroll->rect.x = rect.x;
            file_scroll->rect.y = y;
            file_scroll->rect.width = content_width;
            file_scroll->rect.height = files_height;
            file_scroll->layout();
            y += files_height;
        }

        // 3. Split handle
        if (split_handle) {
            split_handle->rect.x = rect.x;
            split_handle->rect.y = y;
            split_handle->rect.width = content_width;
            split_handle->rect.height = split_handle_height;
            y += split_handle_height;
        }

        // 4. Branch scroll container
        if (branch_scroll) {
            branch_scroll->rect.x = rect.x;
            branch_scroll->rect.y = y;
            branch_scroll->rect.width = content_width;
            branch_scroll->rect.height = branches_height;
            branch_scroll->layout();
        }

        // 5. Drag handle (full height on right side)
        if (drag_handle) {
            drag_handle->rect.x = rect.x + content_width;
            drag_handle->rect.y = rect.y;
            drag_handle->rect.width = Sidebar::DRAG_HANDLE_HIT;
            drag_handle->rect.height = rect.height;
        }
    }

    void render(RenderContext& ctx) override {
        // Sidebar background
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + sidebar_width, rect.y + rect.height
        );
        ctx.fill_rect(bg_rect, Theme::BG_SECONDARY);

        // Render children in order
        if (header) header->render(ctx);
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            commit_header->render(ctx);
        }
        if (file_scroll) file_scroll->render(ctx);

        // Accent border around file list area (commit view mode)
        // Top corners are square to merge with header, bottom corners are rounded
        if (show_file_border && file_scroll) {
            constexpr float border_width = 2.0f;
            float bw2 = border_width / 2.0f;
            float x0 = file_scroll->rect.x + bw2;
            float y0 = file_scroll->rect.y + bw2;
            float x1 = file_scroll->rect.x + file_scroll->rect.width - bw2;
            float y1 = file_scroll->rect.y + file_scroll->rect.height - bw2;
            float r = Theme::CORNER_RADIUS;

            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));

            // Draw border as path: square top corners, rounded bottom corners
            ID2D1PathGeometry* path = nullptr;
            ID2D1Factory* factory = nullptr;
            ctx.target->GetFactory(&factory);
            if (factory && SUCCEEDED(factory->CreatePathGeometry(&path))) {
                ID2D1GeometrySink* sink = nullptr;
                if (SUCCEEDED(path->Open(&sink))) {
                    sink->BeginFigure(D2D1::Point2F(x0, y0), D2D1_FIGURE_BEGIN_HOLLOW);
                    sink->AddLine(D2D1::Point2F(x1, y0));  // Top edge
                    sink->AddLine(D2D1::Point2F(x1, y1 - r));  // Right edge
                    sink->AddArc(D2D1::ArcSegment(
                        D2D1::Point2F(x1 - r, y1), D2D1::SizeF(r, r),
                        0.0f, D2D1_SWEEP_DIRECTION_CLOCKWISE, D2D1_ARC_SIZE_SMALL));
                    sink->AddLine(D2D1::Point2F(x0 + r, y1));  // Bottom edge
                    sink->AddArc(D2D1::ArcSegment(
                        D2D1::Point2F(x0, y1 - r), D2D1::SizeF(r, r),
                        0.0f, D2D1_SWEEP_DIRECTION_CLOCKWISE, D2D1_ARC_SIZE_SMALL));
                    sink->AddLine(D2D1::Point2F(x0, y0));  // Left edge back to start
                    sink->EndFigure(D2D1_FIGURE_END_CLOSED);
                    sink->Close();
                    sink->Release();

                    ctx.target->DrawGeometry(path, ctx.brush, border_width);
                }
                path->Release();
            }
        }

        if (split_handle) split_handle->render(ctx);
        if (branch_scroll) branch_scroll->render(ctx);
        if (drag_handle) drag_handle->render(ctx);
    }

    // Handle split ratio changes from split handle drag
    void handle_split_drag(float delta_y) {
        // Denominator must match what layout() uses: rect.height minus header
        // minus commit_header (when visible). Forgetting commit_header here
        // made the drag feel sluggish whenever the commit header was up.
        float scrollable_height = rect.height;
        if (header) scrollable_height -= header->preferred_height;
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            scrollable_height -= commit_header->rect.height;
        }

        if (scrollable_height > 0) {
            // Delta is in pixels, convert to ratio change
            // Positive delta = dragging down = more files, less branches
            float ratio_delta = delta_y / scrollable_height;
            float new_ratio = split_ratio - ratio_delta;

            // Clamp to valid range
            if (new_ratio < CommitHistory::SPLIT_MIN_RATIO) new_ratio = CommitHistory::SPLIT_MIN_RATIO;
            if (new_ratio > CommitHistory::SPLIT_MAX_RATIO) new_ratio = CommitHistory::SPLIT_MAX_RATIO;

            if (new_ratio != split_ratio) {
                split_ratio = new_ratio;
                layout();
                set_dirty();

                if (on_split_changed) {
                    on_split_changed(this, split_ratio, user_data);
                }
            }
        }
    }

    // Handle width changes from drag handle
    void handle_width_drag(float new_width) {
        if (new_width != sidebar_width) {
            sidebar_width = new_width;
            layout();
            set_dirty();

            if (on_width_changed) {
                on_width_changed(this, sidebar_width, user_data);
            }
        }
    }

    // Hit testing - custom implementation for sidebar bounds
    bool hit_test(float x, float y) const {
        // Check if point is within sidebar bounds (includes drag handle)
        return x >= rect.x && x < rect.x + sidebar_width &&
               y >= rect.y && y < rect.y + rect.height;
    }

    // Forward mouse events to children
    bool on_mouse_down(float x, float y, int button) override {
        // Check drag handle first (rightmost)
        // DragHandle/SplitHandle use ABSOLUTE coordinates for stable drag calculations
        if (drag_handle && drag_handle->hit_test(x, y)) {
            drag_handle->drag_start_width = sidebar_width;
            return drag_handle->on_mouse_down(x, y, button);
        }

        // Check split handle (uses absolute coordinates)
        if (split_handle && split_handle->hit_test(x, y)) {
            return split_handle->on_mouse_down(x, y, button);
        }

        // Check commit header (visible in commit view mode)
        if (commit_header && (commit_header->flags & WidgetFlags::Visible) && commit_header->hit_test(x, y)) {
            return commit_header->on_mouse_down(x - commit_header->rect.x, y - commit_header->rect.y, button);
        }

        // Check scrollable sections (use relative coordinates for internal hit testing)
        if (file_scroll && file_scroll->hit_test(x, y)) {
            return file_scroll->on_mouse_down(x - file_scroll->rect.x, y - file_scroll->rect.y, button);
        }
        if (branch_scroll && branch_scroll->hit_test(x, y)) {
            return branch_scroll->on_mouse_down(x - branch_scroll->rect.x, y - branch_scroll->rect.y, button);
        }

        // Check header
        if (header && header->hit_test(x, y)) {
            return header->on_mouse_down(x - header->rect.x, y - header->rect.y, button);
        }

        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        bool handled = false;

        // Always propagate mouse up to dragging widgets (absolute coordinates)
        if (drag_handle && drag_handle->dragging) {
            drag_handle->on_mouse_up(x, y, button);
            handled = true;
        }
        if (split_handle && split_handle->dragging) {
            split_handle->on_mouse_up(x, y, button);
            handled = true;
        }

        // Forward to commit header (for scrollbar drag release)
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            if (commit_header->on_mouse_up(x - commit_header->rect.x, y - commit_header->rect.y, button)) {
                handled = true;
            }
        }

        // Forward to scroll containers (relative coordinates)
        if (file_scroll) {
            file_scroll->on_mouse_up(x - file_scroll->rect.x, y - file_scroll->rect.y, button);
        }
        if (branch_scroll) {
            branch_scroll->on_mouse_up(x - branch_scroll->rect.x, y - branch_scroll->rect.y, button);
        }

        return handled;
    }

    bool on_mouse_move(float x, float y) override {
        bool handled = false;

        // Handle active drags first (absolute coordinates for stable drag)
        if (drag_handle && drag_handle->dragging) {
            drag_handle->on_mouse_move(x, y);
            return true;
        }
        if (split_handle && split_handle->dragging) {
            split_handle->on_mouse_move(x, y);
            return true;
        }

        // Update hover states
        bool in_drag_handle = drag_handle && drag_handle->hit_test(x, y);
        bool in_split_handle = split_handle && split_handle->hit_test(x, y);

        // Drag handle hover
        if (drag_handle) {
            if (in_drag_handle && !(drag_handle->flags & WidgetFlags::Hovered)) {
                drag_handle->on_mouse_enter();
            } else if (!in_drag_handle && (drag_handle->flags & WidgetFlags::Hovered)) {
                drag_handle->on_mouse_leave();
            }
        }

        // Split handle hover
        if (split_handle) {
            if (in_split_handle && !(split_handle->flags & WidgetFlags::Hovered)) {
                split_handle->on_mouse_enter();
            } else if (!in_split_handle && (split_handle->flags & WidgetFlags::Hovered)) {
                split_handle->on_mouse_leave();
            }
        }

        // Forward to commit header (for close button hover and scrollbar drag)
        // Always forward even outside bounds during scrollbar drag
        if (commit_header && (commit_header->flags & WidgetFlags::Visible)) {
            // Always try forwarding - on_mouse_move returns true if actively dragging scrollbar
            if (commit_header->on_mouse_move(x - commit_header->rect.x, y - commit_header->rect.y)) {
                return true;  // Scrollbar is being dragged, consume event
            }
            // Clear hover if outside bounds
            if (!commit_header->hit_test(x, y)) {
                commit_header->on_mouse_leave();
            }
        }

        // Forward to scroll containers
        if (file_scroll && file_scroll->hit_test(x, y)) {
            file_scroll->on_mouse_move(x - file_scroll->rect.x, y - file_scroll->rect.y);
            handled = true;
        } else if (file_scroll) {
            file_scroll->on_mouse_leave();
        }

        if (branch_scroll && branch_scroll->hit_test(x, y)) {
            branch_scroll->on_mouse_move(x - branch_scroll->rect.x, y - branch_scroll->rect.y);
            handled = true;
        } else if (branch_scroll) {
            branch_scroll->on_mouse_leave();
        }

        // Forward to header
        if (header && header->hit_test(x, y)) {
            header->on_mouse_move(x - header->rect.x, y - header->rect.y);
        }

        return handled;
    }

    bool on_mouse_leave() override {
        // Clear hover states on all children
        if (drag_handle && !drag_handle->dragging) drag_handle->on_mouse_leave();
        if (split_handle && !split_handle->dragging) split_handle->on_mouse_leave();
        if (commit_header) commit_header->on_mouse_leave();
        if (file_scroll) file_scroll->on_mouse_leave();
        if (branch_scroll) branch_scroll->on_mouse_leave();
        if (header) header->on_mouse_leave();
        return false;
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        // Route wheel to the correct scroll container based on cursor position
        // y is relative to sidebar rect, compare against split handle position

        // Check commit header first (for message scrolling)
        if (commit_header && (commit_header->flags & WidgetFlags::Visible) && commit_header->hit_test(x, y)) {
            if (commit_header->on_mouse_wheel(x - commit_header->rect.x, y - commit_header->rect.y, delta)) {
                return true;
            }
        }

        if (split_handle) {
            // Split handle divides file section from branch section
            float split_y = split_handle->rect.y - rect.y;  // Relative to sidebar

            if (y >= split_y) {
                // Below (or on) split handle -> branches section
                if (branch_scroll) {
                    return branch_scroll->on_mouse_wheel(x, y, delta);
                }
            } else {
                // Above split handle -> files section
                if (file_scroll) {
                    return file_scroll->on_mouse_wheel(x, y, delta);
                }
            }
        } else {
            // No split handle, default to file scroll
            if (file_scroll) {
                return file_scroll->on_mouse_wheel(x, y, delta);
            }
        }
        return false;
    }
};
